import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.DRBHoC6Q.js";const s=JSON.parse('{"title":"MVP 后端待确认口径清单","description":"","frontmatter":{},"headers":[],"relativePath":"v3/pending-qa.md","filePath":"v3/pending-qa.md","lastUpdated":1783323851000}'),i={name:"v3/pending-qa.md"};function o(l,t,n,h,p,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="mvp-后端待确认口径清单" tabindex="-1">MVP 后端待确认口径清单 <a class="header-anchor" href="#mvp-后端待确认口径清单" aria-label="Permalink to &quot;MVP 后端待确认口径清单&quot;">​</a></h1><p>文档版本：V0.1<br> 用途：记录不阻塞确定性后端开发、但上线真实数据前需要产品或财务确认的业务口径。</p><h2 id="_1-当前暂行口径" tabindex="-1">1. 当前暂行口径 <a class="header-anchor" href="#_1-当前暂行口径" aria-label="Permalink to &quot;1. 当前暂行口径&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>待确认事项</th><th>当前暂行实现</th><th>影响</th></tr></thead><tbody><tr><td>30/60/90 天预测</td><td>现金安全线是否长期为 0 元</td><td>使用 0 元</td><td>影响缺口金额和跌破日期</td></tr><tr><td>30/60/90 天预测</td><td><code>planned</code>、<code>pending</code> 是否占用预测现金</td><td>两者与 <code>approved</code> 均进入基础预测</td><td>影响预测余额</td></tr><tr><td>30/60/90 天预测</td><td>实际付款数据缺失时如何识别已付款</td><td>依赖计划支出状态及时更新</td><td>可能重复计算支出</td></tr><tr><td>回款风险</td><td>临期是否按自然日还是工作日</td><td>未来 0～2 个自然日为黄色风险</td><td>影响 Top 3 候选</td></tr><tr><td>回款风险</td><td>红色风险阈值</td><td>逾期 30 天，或逾期且未回金额达到 100 万元</td><td>影响老板拍板事件</td></tr><tr><td>付款建议</td><td>计划日期早于基准日的已审批支出如何试算</td><td>视为基准日当天待支付</td><td>避免逾期支出从预测中消失</td></tr><tr><td>付款建议</td><td>同日期、同刚性程度是否需要类别优先级</td><td>按支出编号稳定排序</td><td>影响逐笔试算顺序</td></tr><tr><td>老板拍板</td><td>决定后是否自动生成执行任务</td><td>当前只保存决定，不自动执行</td><td>不影响拍板留痕</td></tr><tr><td>AI 解释</td><td>是否缓存及缓存失效规则</td><td>暂不实现 AI 接口</td><td>不阻塞确定性业务接口</td></tr></tbody></table><h2 id="_2-当前明确不交给-ai-判断的内容" tabindex="-1">2. 当前明确不交给 AI 判断的内容 <a class="header-anchor" href="#_2-当前明确不交给-ai-判断的内容" aria-label="Permalink to &quot;2. 当前明确不交给 AI 判断的内容&quot;">​</a></h2><ul><li>现金余额、缺口金额和日期；</li><li>回款风险等级和 Top 3 排序；</li><li>付款资格、付款顺序和付款建议；</li><li>是否升级老板拍板；</li><li>老板可选处理方案是否合法。</li></ul><p>AI 后续只读取结构化证据生成解释，不修改规则计算结果。</p><h2 id="_3-变更原则" tabindex="-1">3. 变更原则 <a class="header-anchor" href="#_3-变更原则" aria-label="Permalink to &quot;3. 变更原则&quot;">​</a></h2><p>上述口径确认后，应优先调整集中规则参数或共享计算模块，不在控制器、页面接口和前端分别修改，避免同一指标出现多套公式。</p>',9)])])}const m=d(i,[["render",o]]);export{s as __pageData,m as default};
